fn alpaca_incremental_fetch_limit(timeframe: &str, after_timestamp: Option<&str>) -> u32 {
    alpaca_incremental_fetch_limit_at(chrono::Utc::now().timestamp(), timeframe, after_timestamp)
}

fn tastytrade_sync_backoff_secs(error: &str) -> i64 {
    let lower = error.to_ascii_lowercase();
    if tastytrade_quote_streamer_customer_missing(error) {
        24 * 60 * 60
    } else if lower.contains("404") || lower.contains("not found") {
        30 * 60
    } else if lower.contains("401") || lower.contains("403") || lower.contains("unauthorized") {
        15 * 60
    } else if lower.contains("429") {
        10 * 60
    } else if lower.contains("502")
        || lower.contains("503")
        || lower.contains("504")
        || lower.contains("gateway")
    {
        5 * 60
    } else {
        3 * 60
    }
}

fn tastytrade_quote_streamer_customer_missing(error: &str) -> bool {
    let lower = error.to_ascii_lowercase();
    lower.contains("quote_streamer.customer_not_found_error")
        || lower.contains("customer_not_found_error")
        || lower.contains("you must be a customer to access")
}

fn tastytrade_quote_streamer_customer_missing_message(env: &str, error: &str) -> String {
    format!(
        "tastytrade market data unavailable: {env} login authenticated, but tastytrade says this user is not a quote-streamer customer. Create/attach a customer account for this {env} user or switch to a funded production account. Raw error: {error}"
    )
}

/// Log severity level.
#[derive(Clone, Copy, Debug)]
enum LogLevel {
    Info,
    Warn,
    Error,
    Trade, // ADR-094: fills, executions
    Alert, // ADR-094: triggered alerts
}

/// Log filter for the bottom panel dropdown.
#[derive(Clone, Copy, PartialEq)]
enum LogFilter {
    All,
    Info,
    Warn,
    Error,
    Trade,
    Alert,
}

/// A single log entry displayed in the bottom panel.
#[derive(Clone, Debug)]
struct LogEntry {
    level: LogLevel,
    msg: String,
    /// PERF: pre-formatted display text `"[HH:MM:SS] <icon> <msg>"` built once
    /// at construction. The bottom-panel log was calling `format!()` per entry
    /// per frame (~200 entries × 60fps = 12k allocs/sec) for a string that
    /// never changes once created. `timestamp` is folded into this buffer.
    display: String,
}

